1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	interface QuoteStep {
5	  op: "quote";
6	  items: { type: string }[];
7	}
8	
9	interface Scenario {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	}
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	};
20	
21	const quotePremium = (step: QuoteStep): number => {
22	  const itemsPremium = step.items.reduce((sum, item) => {
23	    const basePremium = BASE_PREMIUMS[item.type];
24	    return sum + basePremium * (1 + FIRST_INSURANCE_SURCHARGE);
25	  }, 0);
26	  const total = itemsPremium + PROCESSING_FEE;
27	  return Math.ceil(Number(total.toFixed(6)));
28	};
29	
30	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
31	  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
32	};
